Use MSTest's `[DataTestMethod]` with `[DataRow]` to make these parameterized. All 9 cases collapse into one method:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    [DataTestMethod]
    [DataRow("",                false, "Input cannot be empty",                DisplayName = "Empty string")]
    [DataRow(null,              false, "Input cannot be empty",                DisplayName = "Null")]
    [DataRow("   ",             false, "Input cannot be empty",                DisplayName = "Whitespace only")]
    [DataRow("ab",              false, "Input must be at least 3 characters",  DisplayName = "Too short")]
    [DataRow("hello<script>",   false, "Input contains invalid characters",    DisplayName = "Special chars")]
    [DataRow("hello-world",     true,  null,                                   DisplayName = "Valid input")]
    [DataRow("abc",             true,  null,                                   DisplayName = "Min length boundary")]
    public void Validate_ReturnsExpectedResult(
        string? input, bool expectedIsValid, string? expectedError)
    {
        var validator = new InputValidator();
        var result = validator.Validate(input);
        Assert.AreEqual(expectedIsValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    // DataRow requires compile-time constants, so generated strings use DynamicData
    private static IEnumerable<object?[]> GeneratedInputCases =>
    [
        [new string('x', 256), false, "Input must not exceed 255 characters"],
        [new string('a', 255), true,  null],
    ];

    [DataTestMethod]
    [DynamicData(nameof(GeneratedInputCases))]
    public void Validate_GeneratedInput_ReturnsExpectedResult(
        string input, bool expectedIsValid, string? expectedError)
    {
        var validator = new InputValidator();
        var result = validator.Validate(input);
        Assert.AreEqual(expectedIsValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }
}
```

**Key points:**

- **`[DataRow]`** — handles all cases with literal/constant inputs. Adding a new case is one line.
- **`[DynamicData]`** — handles cases needing runtime-generated inputs (like `new string('x', 256)`).
- **`DisplayName`** — gives each row a readable name in Test Explorer.
- Each `[DataRow]` shows as a separate test result, so you still get per-case pass/fail visibility.
